#nullable enable // autogenerated

using MVZ2.Vanilla.Properties;
using MVZ2Logic;
using MVZ2Logic.Callbacks;
using MVZ2Logic.Level;
using PVZEngine;
using PVZEngine.Callbacks;
using PVZEngine.Definitions;
using PVZEngine.Entities;
using UnityEngine;

namespace MVZ2.GameContent.Effects
{
    [AutoEntityBehaviourDefinition(VanillaEffectNames.minecartRideable)]
    public class MinecartRideable : EntityBehaviourDefinition
    {
        public MinecartRideable(string nsp, string name) : base(nsp, name)
        {
            AddTrigger(LogicLevelCallbacks.POST_PAUSE, PostPauseCallback);
        }
        public override void Init(Entity entity)
        {
            base.Init(entity);
            SetTargetPosition(entity, entity.Position);
        }
        public override void Update(Entity entity)
        {
            base.Update(entity);
            if (Global.Input.TryGetPointerScreenPosition(out var screenPosition) && entity.Level.IsGameRunning())
            {
                var targetPosition = entity.Level.ScreenToLawnPositionByRelativeY(screenPosition, 0);
                SetTargetPosition(entity, targetPosition);
            }

            var parent = entity.Parent;
            if (parent.ExistsAndAlive())
            {
                FollowPointer(entity, parent, GetTargetPosition(entity));
            }
        }
        private void FollowPointer(Entity entity, Entity parent, Vector3 targetPosition)
        {
            var parentBounds = parent.GetBounds();
            var entityBounds = entity.GetBounds();
            var minX = parentBounds.min.x + entityBounds.extents.x;
            var maxX = parentBounds.max.x - entityBounds.extents.x;
            var minZ = parentBounds.min.z + entityBounds.extents.z;
            var maxZ = parentBounds.max.z - entityBounds.extents.z;
            targetPosition.x = minX < maxX ? Mathf.Clamp(targetPosition.x, minX, maxX) : parent.Position.x;
            targetPosition.z = minZ < maxZ ? Mathf.Clamp(targetPosition.z, minZ, maxZ) : parent.Position.z;
            var distance = targetPosition - entity.Position;
            var magnitude = Mathf.Max(0, distance.magnitude - 24f);
            distance = magnitude * distance.normalized;
            var targetVelocity = distance * VELOCITY_DAMP;
            entity.Velocity = targetVelocity;
        }
        private void PostPauseCallback(LevelCallbackParams param, CallbackResult result)
        {
            var level = param.level;
            foreach (var cart in level.FindEntities(e => e.HasBehaviour(this)))
            {
                cart.Velocity = Vector3.zero;
                SetTargetPosition(cart, cart.Position);
            }
        }
        public static Vector3 GetTargetPosition(Entity entity) => entity.GetBehaviourField<Vector3>(PROP_TARGET_POSITION);
        public static void SetTargetPosition(Entity entity, Vector3 value) => entity.SetBehaviourField(PROP_TARGET_POSITION, value);
        public const float VELOCITY_DAMP = 0.1f;
        public static readonly VanillaEntityPropertyMeta<Vector3> PROP_TARGET_POSITION = new VanillaEntityPropertyMeta<Vector3>("target_position");
    }
}